const input = $input.first().json;

const data =
  input.body && Object.keys(input.body).length > 0
    ? input.body
    : input.query && Object.keys(input.query).length > 0
      ? input.query
      : input;

function clean(value, fallback = '') {
  return String(value ?? fallback).trim();
}

function money(value) {
  const parsed = Number(String(value ?? 0).replace(/,/g, ''));
  return Number.isFinite(parsed) ? parsed : 0;
}

const applicationId = 'FIN-APP-' + Date.now();
const nombre = clean(data.nombre || data.name);

return [
  {
    json: {
      application_id: applicationId,
      nombre,
      email: clean(data.email || data.correo).toLowerCase(),
      telefono: clean(data.telefono || data.phone || data.celular),
      ciudad: clean(data.ciudad || data.city),
      tipo_propiedad: clean(data.tipo_propiedad || data.property_type || 'Otro'),
      valor_propiedad: money(data.valor_propiedad || data.property_value),
      enganche_disponible: money(data.enganche_disponible || data.down_payment),
      ingreso_mensual: money(data.ingreso_mensual || data.monthly_income),
      plazo_deseado_anios: Number(data.plazo_deseado_anios || data.plazo || data.term_years || 0),
      mensaje: clean(data.mensaje || data.message),
      fecha_registro: new Date().toISOString().slice(0, 10),
      folder_name: `FIN-${applicationId} - ${nombre}`,
      json_original: JSON.stringify(data)
    }
  }
];

const item = $input.first().json;
const errores = [];

const allowedPropertyTypes = ['Casa', 'Departamento', 'Terreno', 'Local comercial', 'Otro'];

if (!item.nombre || item.nombre.length < 2) errores.push('Nombre inválido o vacío');
if (!item.email || !item.email.includes('@')) errores.push('Email inválido o vacío');
if (!item.telefono || item.telefono.length < 7) errores.push('Teléfono inválido o vacío');
if (!item.ciudad || item.ciudad.length < 2) errores.push('Ciudad inválida o vacía');
if (!allowedPropertyTypes.includes(item.tipo_propiedad)) errores.push('Tipo de propiedad inválido');
if (!item.valor_propiedad || item.valor_propiedad <= 0) errores.push('Valor de propiedad inválido');
if (item.enganche_disponible < 0) errores.push('Enganche disponible inválido');
if (item.enganche_disponible > item.valor_propiedad) errores.push('El enganche no puede ser mayor al valor de la propiedad');
if (!item.ingreso_mensual || item.ingreso_mensual <= 0) errores.push('Ingreso mensual inválido');
if (!item.plazo_deseado_anios || item.plazo_deseado_anios <= 0) errores.push('Plazo deseado inválido');
if (!item.mensaje || item.mensaje.length < 5) errores.push('Mensaje inválido o vacío');

return [
  {
    json: {
      ...item,
      valido: errores.length === 0,
      errores_validacion: errores
    }
  }
];

const item = $input.first().json;

const valorPropiedad = Number(item.valor_propiedad);
const enganche = Number(item.enganche_disponible);
const ingresoMensual = Number(item.ingreso_mensual);
const plazoAnios = Number(item.plazo_deseado_anios);

const montoFinanciar = Math.max(valorPropiedad - enganche, 0);
const porcentajeEnganche = valorPropiedad > 0 ? (enganche / valorPropiedad) * 100 : 0;

// Demo calculation only: estimated monthly payment using a fixed illustrative annual rate.
const annualRate = 0.12;
const monthlyRate = annualRate / 12;
const months = plazoAnios * 12;
let pagoEstimadoMensual = 0;

if (montoFinanciar > 0 && months > 0) {
  pagoEstimadoMensual = montoFinanciar * monthlyRate * Math.pow(1 + monthlyRate, months) / (Math.pow(1 + monthlyRate, months) - 1);
}

const relacionPagoIngreso = ingresoMensual > 0 ? (pagoEstimadoMensual / ingresoMensual) * 100 : 999;

let resultadoPrecalificacion = 'No viable';
let prioridad = 'Baja';
let estado = 'Rechazada';
let diasContacto = 5;

if (porcentajeEnganche >= 20 && relacionPagoIngreso <= 35) {
  resultadoPrecalificacion = 'Preaprobado';
  prioridad = 'Alta';
  estado = 'Preaprobada';
  diasContacto = 0;
} else if (porcentajeEnganche >= 10 && relacionPagoIngreso <= 45) {
  resultadoPrecalificacion = 'Requiere revisión';
  prioridad = 'Media';
  estado = 'En revisión';
  diasContacto = 2;
}

const fechaContacto = new Date();
fechaContacto.setDate(fechaContacto.getDate() + diasContacto);

return [
  {
    json: {
      ...item,
      monto_financiar: Number(montoFinanciar.toFixed(2)),
      porcentaje_enganche: Number(porcentajeEnganche.toFixed(2)),
      pago_estimado_mensual: Number(pagoEstimadoMensual.toFixed(2)),
      relacion_pago_ingreso: Number(relacionPagoIngreso.toFixed(2)),
      resultado_precalificacion: resultadoPrecalificacion,
      prioridad,
      estado,
      fecha_sugerida_contacto: fechaContacto.toISOString().slice(0, 10),
      task_id: 'FIN-TASK-' + Date.now()
    }
  }
];

