const ai = $node['OpenAI - Analizar Solicitud'].json;
let text = '';

if (ai.output_text) {
  text = ai.output_text;
} else if (ai.output?.[0]?.content?.[0]?.text) {
  text = ai.output[0].content[0].text;
} else if (ai.choices?.[0]?.message?.content) {
  text = ai.choices[0].message.content;
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (error) {
  parsed = {
    resumen_ia: 'No se pudo parsear correctamente la respuesta de IA.',
    siguiente_accion: 'Revisar la solicitud manualmente.',
    notas_riesgo: 'Respuesta de IA no estructurada.'
  };
}

return [
  {
    json: {
      ...$node['Calcular Precalificación'].json,
      resumen_ia: parsed.resumen_ia,
      siguiente_accion: parsed.siguiente_accion,
      notas_riesgo: parsed.notas_riesgo,
      ai_raw_response: JSON.stringify(ai)
    }
  }
];
